import { Button, FormHelperText, MenuItem, TextField } from '@material-ui/core'
import axios from 'axios'
import React, { useState } from 'react'
import { useNavigate } from 'react-router-dom'



export default function CreateAdmin() {
    const history = useNavigate();
    const [data, setData] = useState({
        firstName: '',
        middleName: '',
        lastName: '',
        studentID: '',
        college: '',
        course: '',
        password: ''
    })

    const handleChange = (event) => {
        const name = event.target.name;
        const value = event.target.value;

        setData(data => ({...data, [name]: value}));
    }

    const handleSubmitStudent = () => {
        const sendData = {
            firstName:data.firstName,
            middleName:data.middleName,
            lastName:data.lastName,
            studentID:data.studentID,
            college: data.college,
            course: data.course,
            password:data.password
        }
        axios.post('http://localhost:80/api/registerStudent.php', sendData)
        .then((result) => {
            console.log(result.data)
        })
        .catch(err => console.log(err))
    };

    const handleSubmitTeacher = () => {
      const sendData = {
          firstName:data.firstName,
          middleName:data.middleName,
          lastName:data.lastName,
          instructorID:data.instructorID,
          college: data.college,
          course: data.course,
          password:data.password
      }
      axios.post('http://localhost:80/api/registerTeacher.php', sendData)
      .then((result) => {
          console.log(result.data)
      })
      .catch(err => console.log(err))
  };

  const handleSubmitAdmin = () => {
    const sendData = {
        username:data.username,
        firstName:data.firstName,
        lastName:data.lastName,
        adminID:data.adminID,
        password:data.password
    }
    axios.post('http://localhost:80/api/registerStudent.php', sendData)
    .then((result) => {
        console.log(result.data)
    })
    .catch(err => console.log(err))
};

      
  const [position, setPosition] = useState('Student')

  const [teacherPosition, setTeacherPosition] = useState(false)
  const [adminPosition, setAdminPosition] = useState(false)

    
   const handleChangeSelect = (event) => {
    setPosition(event.target.value);
    if(event.target.value === 'Instructor') {
      setTeacherPosition(true)
      setAdminPosition(false)
    } else if (event.target.value === 'Admin') {
      setTeacherPosition(false)
      setAdminPosition(true)
    } else {
      setTeacherPosition(false)
      setAdminPosition(false)
    }
   }

  return (
    
    <div>
        
        <center>
          <FormHelperText>Select position.</FormHelperText>
        <TextField variant='outlined' select value={position} onChange={handleChangeSelect} fullWidth>
            <MenuItem value='Student'> Student </MenuItem>
            <MenuItem value='Instructor'> Instructor </MenuItem>
            <MenuItem value='Admin'> Admin </MenuItem>
          </TextField>
            <br /><br />

          {/* ADMIN */}
    {adminPosition ? 
     <div>
     <h1>Create Admin</h1>
     <br />
     <form onSubmit={handleSubmitAdmin}>

     
         <TextField variant='outlined' placeholder='Username'  type="text" name='username' value={data.firstName} onChange={handleChange} fullWidth/>
         <br /><br />

         <TextField variant='outlined' placeholder='Username'  type="text" name='firstName' value={data.firstName} onChange={handleChange} fullWidth/>
         <br /><br />

         <TextField variant='outlined' placeholder='Username'  type="text" name='lastName' value={data.firstName} onChange={handleChange} fullWidth/>
         <br /><br />
         
     
